import boto3
from botocore.exceptions import ClientError

sns = boto3.client('sns')

def create_subscription(topic_arn):
    user_input = input("Enter the URL to subscribe: ")
    try:
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_input
        )
        print(f"Subscription created with ARN: {response['SubscriptionArn']}")
    except ClientError as e:
        if e.response['Error']['Code'] == 'InvalidParameter':
            print("Invalid URL provided. Please check the URL and try again.")
        else:
            print(e)

def main():
    topic_arn = input("Enter your SNS Topic ARN: ")
    create_subscription(topic_arn)

if __name__ == "__main__":
    main()